/**
 * Offline Simulation — AST-31
 *
 * Computes what would have happened while the player was away.
 * Uses simplified averages (skip pathfinding, skip rendering) to estimate:
 * - Resources mined by Miner robots
 * - Research generated by Researcher robots
 * - Refining that would have completed
 *
 * Caps at 8 hours of offline time.
 * Modifies the SaveData in-place so the loaded game starts with gains applied.
 */

import type { SaveData } from './saveLoad';

// ── Constants ─────────────────────────────────────────────────────────────────

export const MAX_OFFLINE_MS = 8 * 60 * 60 * 1000; // 8 hours

/** Robot type indices (mirror robotProfiles.ts ROBOT_TYPES) */
const RT_SCOUT = 0;
const RT_MINER = 1;
const RT_HAULER = 2;
const RT_RESEARCHER = 3;
const RT_REFINER = 4;
// 5 = Defender, 6 = Engineer (no offline yield)

/**
 * Ore yield per Miner per second (simplified average across asteroid types).
 * Distributed across ore types based on typical field composition.
 */
const MINER_ORE_RATE: Partial<Record<string, number>> = {
  iron: 2.0,
  carbon: 0.8,
  nickel: 0.6,
  silicate: 0.5,
  ice: 0.3,
  cobalt: 0.15,
  platinum: 0.05,
};

/** Basic refining conversion (used when refineryBuilt = true) */
const REFINERY_RATE_PER_SEC = 1.5; // refined_iron per second (approximate)

/** Scout anomaly chance per second (probability of finding an anomaly) */
const SCOUT_ANOMALY_CHANCE_PER_SEC = 0.0005;

// ── Result type ───────────────────────────────────────────────────────────────

export interface OfflineResult {
  /** Raw elapsed time since save */
  elapsedMs: number;
  /** Elapsed time actually simulated (capped at MAX_OFFLINE_MS) */
  cappedMs: number;
  /** Whether the cap was applied */
  wasCapped: boolean;
  /** Human-readable elapsed time string */
  elapsedLabel: string;
  /** Resources added to base storage */
  resourcesGained: Record<string, number>;
  /** Refined materials added (if refinery was built) */
  refinedGained: Record<string, number>;
  /** Research points accumulated */
  researchGained: number;
  /** Estimated anomalies that scouts may have found */
  anomaliesFound: number;
  /** Robot counts by type for the report */
  robotCounts: {
    miners: number;
    scouts: number;
    haulers: number;
    researchers: number;
    refiners: number;
  };
  /** Approximate ticks that elapsed */
  ticksSimulated: number;
}

// ── Core function ─────────────────────────────────────────────────────────────

/**
 * Apply offline progression to a save file before loading.
 * Modifies save data in-place.
 * Returns a summary for the morning-after report.
 */
export function computeOfflineProgress(save: SaveData, nowMs: number): OfflineResult {
  const elapsedMs = Math.max(0, nowMs - save.timestamp);
  const cappedMs = Math.min(elapsedMs, MAX_OFFLINE_MS);
  const wasCapped = elapsedMs > MAX_OFFLINE_MS;
  const elapsedSec = cappedMs / 1000;

  // Count robots by type
  let miners = 0;
  let scouts = 0;
  let haulers = 0;
  let researchers = 0;
  let refiners = 0;

  for (const r of save.robots) {
    switch (r.robotType) {
      case RT_MINER:
        miners++;
        break;
      case RT_SCOUT:
        scouts++;
        break;
      case RT_HAULER:
        haulers++;
        break;
      case RT_RESEARCHER:
        researchers++;
        break;
      case RT_REFINER:
        refiners++;
        break;
    }
  }

  // ── Mining yield ──────────────────────────────────────────────────────────

  const resourcesGained: Record<string, number> = {};

  if (miners > 0) {
    for (const [ore, rate] of Object.entries(MINER_ORE_RATE)) {
      resourcesGained[ore] = miners * (rate ?? 0) * elapsedSec;
    }
  }

  // Apply hauler efficiency bonus (more haulers = more effective mining)
  const haulerBonus = Math.min(1 + haulers * 0.05, 1.5);
  for (const ore of Object.keys(resourcesGained)) {
    resourcesGained[ore] *= haulerBonus;
  }

  // Add to base storage
  save.base.iron = (save.base.iron ?? 0) + (resourcesGained.iron ?? 0);
  save.base.carbon = (save.base.carbon ?? 0) + (resourcesGained.carbon ?? 0);
  save.base.nickel = (save.base.nickel ?? 0) + (resourcesGained.nickel ?? 0);
  save.base.silicate = (save.base.silicate ?? 0) + (resourcesGained.silicate ?? 0);
  save.base.ice = (save.base.ice ?? 0) + (resourcesGained.ice ?? 0);
  save.base.cobalt = (save.base.cobalt ?? 0) + (resourcesGained.cobalt ?? 0);
  save.base.platinum = (save.base.platinum ?? 0) + (resourcesGained.platinum ?? 0);

  // ── Refining yield ────────────────────────────────────────────────────────

  const refinedGained: Record<string, number> = {};

  if (save.refineryBuilt && refiners > 0) {
    const refinerMultiplier = Math.min(refiners, 3); // diminishing returns
    const ironRefined = REFINERY_RATE_PER_SEC * refinerMultiplier * elapsedSec;
    refinedGained.refined_iron = ironRefined;
    // Deduct raw iron used
    const ironUsed = ironRefined * 1.25; // ~10 iron → 8 refined_iron
    save.base.iron = Math.max(0, (save.base.iron ?? 0) - ironUsed);
    // Add to refined storage
    save.refinedMaterials = save.refinedMaterials ?? {};
    save.refinedMaterials.refined_iron = (save.refinedMaterials.refined_iron ?? 0) + ironRefined;
  }

  // ── Research ──────────────────────────────────────────────────────────────
  // Research does NOT accrue offline — it's an active-play mechanic.
  const researchGained = 0;

  // ── Anomaly discovery ─────────────────────────────────────────────────────

  // Simplified: scouts have a small chance per second of finding something
  let anomaliesFound = 0;
  if (scouts > 0) {
    const totalChance = scouts * SCOUT_ANOMALY_CHANCE_PER_SEC * elapsedSec;
    // Use simple deterministic approximation (not RNG since we don't have seed)
    anomaliesFound = Math.floor(totalChance);
  }

  return {
    elapsedMs,
    cappedMs,
    wasCapped,
    elapsedLabel: formatElapsed(cappedMs),
    resourcesGained,
    refinedGained,
    researchGained,
    anomaliesFound,
    robotCounts: { miners, scouts, haulers, researchers, refiners },
    ticksSimulated: Math.round(cappedMs / (1000 / 60)),
  };
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function formatElapsed(ms: number): string {
  const totalSec = Math.round(ms / 1000);
  const hrs = Math.floor(totalSec / 3600);
  const mins = Math.floor((totalSec % 3600) / 60);
  const secs = totalSec % 60;

  if (hrs > 0) {
    return mins > 0 ? `${hrs}h ${mins}m` : `${hrs}h`;
  }
  if (mins > 0) {
    return secs > 0 ? `${mins}m ${secs}s` : `${mins}m`;
  }
  return `${secs}s`;
}

/**
 * Returns true if the save is old enough to warrant showing a morning-after report.
 * Threshold: at least 2 minutes of elapsed time.
 */
export function shouldShowMorningReport(save: SaveData, nowMs: number): boolean {
  return nowMs - save.timestamp >= 2 * 60 * 1000;
}
